1	/**
2	 * Tests for the /trust page's pure management ops over the staff trust ledger
3	 * (`reset`/`graduate`/`degrade`) and the `summarizeTrust` projection.
4	 *
5	 * These are operator OVERRIDES of autonomy, distinct from `applyDecision`
6	 * (which moves trust as a side effect of a single Approve/Reject). Contracts:
7	 *   - reset wipes stats to zero/"ask";
8	 *   - graduate forces "auto" AND lifts the streak to the threshold (so the
9	 *     engine, which graduates off `consecutiveApprovals`, doesn't undo it);
10	 *   - degrade forces "ask" + zero streak but keeps the totals;
11	 *   - every op is immutable (never touches the input manifest);
12	 *   - management ops never append to the decision `log`.
13	 */
14	import { describe, expect, it } from "vitest";
15	import {
16	  CTO_GRADUATION_THRESHOLD,
17	  EMPTY_CTO_DECISIONS_MANIFEST,
18	  applyDecision,
19	  type CtoDecisionsManifest,
20	} from "@dashboard/lib/cto/decisions";
21	import {
22	  applyTrustOp,
23	  degradeAction,
24	  graduateAction,
25	  resetAction,
26	  summarizeTrust,
27	} from "@dashboard/lib/cto/trust-ops";
28	
29	/** Build a manifest with N consecutive approvals already banked for qa/fix. */
30	function withApprovals(n: number): CtoDecisionsManifest {
31	  let m: CtoDecisionsManifest = structuredClone(EMPTY_CTO_DECISIONS_MANIFEST);
32	  for (let i = 0; i < n; i++) {
33	    m = applyDecision(m, {
34	      staff: "qa",
35	      action: "fix",
36	      taskNumber: 100 + i,
37	      decision: "approve",
38	    });
39	  }
40	  return m;
41	}
42	
43	describe("graduateAction", () => {
44	  it("forces auto and lifts the streak to the threshold", () => {
45	    const before = withApprovals(3);
46	    const after = graduateAction(before, "qa", "fix");
47	    expect(after.staff.qa.fix.mode).toBe("auto");
48	    expect(after.staff.qa.fix.consecutiveApprovals).toBe(
49	      CTO_GRADUATION_THRESHOLD,
50	    );
51	    // Totals preserved.
52	    expect(after.staff.qa.fix.approvals).toBe(3);
53	  });
54	
55	  it("creates the action block when the staff/action is brand new", () => {
56	    const after = graduateAction(
57	      EMPTY_CTO_DECISIONS_MANIFEST,
58	      "coo",
59	      "execute",
60	    );
61	    expect(after.staff.coo.execute.mode).toBe("auto");
62	    expect(after.staff.coo.execute.consecutiveApprovals).toBe(
63	      CTO_GRADUATION_THRESHOLD,
64	    );
65	  });
66	
67	  it("does not mutate the input manifest", () => {
68	    const before = withApprovals(3);
69	    const snapshot = structuredClone(before);
70	    graduateAction(before, "qa", "fix");
71	    expect(before).toEqual(snapshot);
72	  });
73	});
74	
75	describe("degradeAction", () => {
76	  it("forces ask and zeroes the streak but keeps totals", () => {
77	    const before = graduateAction(withApprovals(11), "qa", "fix");
78	    const after = degradeAction(before, "qa", "fix");
79	    expect(after.staff.qa.fix.mode).toBe("ask");
80	    expect(after.staff.qa.fix.consecutiveApprovals).toBe(0);
81	    expect(after.staff.qa.fix.approvals).toBe(11);
82	  });
83	});
84	
85	describe("resetAction", () => {
86	  it("wipes everything back to zero/ask", () => {
87	    const after = resetAction(withApprovals(5), "qa", "fix");
88	    expect(after.staff.qa.fix).toEqual({
89	      approvals: 0,
90	      rejections: 0,
91	      consecutiveApprovals: 0,
92	      mode: "ask",
93	    });
94	  });
95	});
96	
97	describe("management ops never touch the decision log", () => {
98	  it("leaves the log untouched across all three ops", () => {
99	    const before = withApprovals(4);
100	    const logLen = before.log.length;
101	    expect(resetAction(before, "qa", "fix").log).toHaveLength(logLen);
102	    expect(graduateAction(before, "qa", "fix").log).toHaveLength(logLen);
103	    expect(degradeAction(before, "qa", "fix").log).toHaveLength(logLen);
104	  });
105	});
106	
107	describe("applyTrustOp dispatch", () => {
108	  it("routes each op name to the right transform", () => {
109	    const base = withApprovals(2);
110	    expect(applyTrustOp(base, "graduate", "qa", "fix").staff.qa.fix.mode).toBe(
111	      "auto",
112	    );
113	    expect(
114	      applyTrustOp(base, "reset", "qa", "fix").staff.qa.fix
115	        .consecutiveApprovals,
116	    ).toBe(0);
117	    expect(applyTrustOp(base, "degrade", "qa", "fix").staff.qa.fix.mode).toBe(
118	      "ask",
119	    );
120	  });
121	});
122	
123	describe("summarizeTrust", () => {
124	  it("groups actions under staff and attaches the duties that run as them", () => {
125	    const manifest = graduateAction(withApprovals(2), "qa", "fix");
126	    const views = summarizeTrust(manifest, [
127	      { slug: "qa-sweep", staff: "qa" },
128	      { slug: "qa-verify", staff: "qa" },
129	      { slug: "orphan", staff: null },
130	    ]);
131	    const qa = views.find((v) => v.staff === "qa");
132	    expect(qa).toBeTruthy();
133	    expect(qa!.duties).toEqual(["qa-sweep", "qa-verify"]);
134	    expect(qa!.actions[0]?.action).toBe("fix");
135	    expect(qa!.hasAuto).toBe(true);
136	  });
137	
138	  it("includes a staff named only by a duty (no trust recorded yet)", () => {
139	    const views = summarizeTrust(EMPTY_CTO_DECISIONS_MANIFEST, [
140	      { slug: "docs-readme", staff: "tech-writer" },
141	    ]);
142	    const tw = views.find((v) => v.staff === "tech-writer");
143	    expect(tw).toBeTruthy();
144	    expect(tw!.actions).toHaveLength(0);
145	    expect(tw!.duties).toEqual(["docs-readme"]);
146	  });
147	
148	  it("computes remaining + progress toward the threshold", () => {
149	    const manifest = withApprovals(4);
